const Auth={async renderLogin(e){e.innerHTML='\n      <div style="min-height:100vh;display:flex;align-items:center;justify-content:center;padding:24px;">\n        <div style="width:100%;max-width:400px;">\n          <div style="text-align:center;margin-bottom:32px;">\n            <img src="/assets/LogotipoCapitalizarme%20vertical-14.png" alt="Logo" style="max-width:120px;margin-bottom:16px;">\n            <p style="color:#6b7280;font-size:14px;margin-top:4px;">Inicia sesión para continuar</p>\n          </div>\n          <div class="card" style="padding:32px;">\n            <div id="login-error" class="alert alert-error" style="display:none;"></div>\n            <div class="form-group">\n              <label>Usuario</label>\n              <input type="text" id="login-username" placeholder="Ingresa tu usuario" autocomplete="username">\n            </div>\n            <div class="form-group">\n              <label>Contraseña</label>\n              <input type="password" id="login-password" placeholder="Ingresa tu contraseña" autocomplete="current-password">\n            </div>\n            <button class="btn btn-primary" onclick="Auth.iniciarSesion()" style="width:100%;justify-content:center;padding:12px;margin-top:8px;">\n              Ingresar\n            </button>\n            <p style="text-align:center;margin-top:16px;font-size:13px;color:#6b7280;">\n              ¿Primera vez? <span onclick="Auth.mostrarRegistro()" style="color:#D4AF37;cursor:pointer;">Crear cuenta</span>\n            </p>\n          </div>\n        </div>\n      </div>\n    ',document.getElementById("topbar").style.display="none",document.getElementById("login-username")?.focus()},async renderRegister(e){e.innerHTML='\n      <div style="min-height:100vh;display:flex;align-items:center;justify-content:center;padding:24px;">\n        <div style="width:100%;max-width:400px;">\n          <div style="text-align:center;margin-bottom:32px;">\n            <img src="/assets/LogotipoCapitalizarme%20vertical-14.png" alt="Logo" style="max-width:120px;margin-bottom:16px;">\n            <p style="color:#6b7280;font-size:14px;margin-top:4px;">Crear nueva cuenta</p>\n          </div>\n          <div class="card" style="padding:32px;">\n            <div id="register-error" class="alert alert-error" style="display:none;"></div>\n            <div id="register-success" class="alert alert-success" style="display:none;"></div>\n            <div class="form-group">\n              <label>Usuario</label>\n              <input type="text" id="reg-username" placeholder="Elige un nombre de usuario">\n            </div>\n            <div class="form-group">\n              <label>Contraseña</label>\n              <input type="password" id="reg-password" placeholder="Mínimo 4 caracteres">\n            </div>\n            <div class="form-group">\n              <label>Confirmar contraseña</label>\n              <input type="password" id="reg-confirm" placeholder="Repite la contraseña">\n            </div>\n            <button class="btn btn-primary" onclick="Auth.registrar()" style="width:100%;justify-content:center;padding:12px;margin-top:8px;">\n              Crear cuenta\n            </button>\n            <p style="text-align:center;margin-top:16px;font-size:13px;color:#6b7280;">\n              ¿Ya tienes cuenta? <span onclick="Auth.mostrarLogin()" style="color:#D4AF37;cursor:pointer;">Iniciar sesión</span>\n            </p>\n          </div>\n        </div>\n      </div>\n    ',document.getElementById("topbar").style.display="none"},mostrarRegistro(){const e=document.getElementById("main-content");this.renderRegister(e)},mostrarLogin(){const e=document.getElementById("main-content");this.renderLogin(e)},async iniciarSesion(){const e=document.getElementById("login-username").value.trim(),t=document.getElementById("login-password").value,n=document.getElementById("login-error");if(!e||!t)return n.textContent="Completa todos los campos",void(n.style.display="block");try{const n=await API.login({username:e,password:t});localStorage.setItem("token",n.token),localStorage.setItem("user",JSON.stringify(n.usuario)),window.location.hash="#/"}catch(e){n.textContent=e.message,n.style.display="block"}},async registrar(){const e=document.getElementById("reg-username").value.trim(),t=document.getElementById("reg-password").value,n=document.getElementById("reg-confirm").value,o=document.getElementById("register-error"),a=document.getElementById("register-success");if(o.style.display="none",a.style.display="none",!e||!t||!n)return o.textContent="Completa todos los campos",void(o.style.display="block");if(t!==n)return o.textContent="Las contraseñas no coinciden",void(o.style.display="block");try{await API.register({username:e,password:t}),a.textContent="Cuenta creada correctamente. Redirigiendo al login...",a.style.display="block",setTimeout(()=>Auth.mostrarLogin(),1500)}catch(e){o.textContent=e.message,o.style.display="block"}},async logout(){try{await API.logout()}catch{}localStorage.removeItem("token"),localStorage.removeItem("user"),window.location.hash="#/login",window.location.reload()}};